"""matplotlib.mlab — numerical utilities."""

import numpy as _np


def detrend_none(x, axis=None):
    return _np.asarray(x)


def detrend_mean(x, axis=None):
    x = _np.asarray(x)
    return x - x.mean(axis=axis, keepdims=True)


def detrend_linear(y):
    y = _np.asarray(y, dtype=float)
    n = len(y)
    x = _np.arange(n, dtype=float)
    C = _np.cov(x, y, bias=True)
    b = C[0, 1] / max(C[0, 0], 1e-10)
    a = y.mean() - b * x.mean()
    return y - (b * x + a)


def stride_windows(x, n, noverlap=0, axis=0):
    x = _np.asarray(x)
    step = n - noverlap
    shape = ((x.shape[axis] - noverlap) // step, n) + x.shape[1:]
    return _np.zeros(shape)


def psd(x, NFFT=256, Fs=2, detrend=detrend_none, window=None,
        noverlap=0, pad_to=None, sides='default', scale_by_freq=None):
    N = len(x)
    if NFFT > N:
        NFFT = N
    freqs = _np.fft.rfftfreq(NFFT, d=1.0/Fs)
    spec = _np.abs(_np.fft.rfft(x[:NFFT]))**2 / NFFT
    return spec, freqs


def csd(x, y, NFFT=256, Fs=2, detrend=detrend_none, window=None,
        noverlap=0, pad_to=None, sides='default', scale_by_freq=None):
    px, freqs = psd(x, NFFT, Fs)
    py, _ = psd(y, NFFT, Fs)
    return px * py, freqs


def cohere(x, y, NFFT=256, Fs=2, detrend=detrend_none, window=None,
           noverlap=0, pad_to=None, sides='default', scale_by_freq=None):
    Pxy, freqs = csd(x, y, NFFT, Fs)
    Pxx, _ = psd(x, NFFT, Fs)
    Pyy, _ = psd(y, NFFT, Fs)
    C = _np.abs(Pxy)**2 / (_np.maximum(Pxx * Pyy, 1e-10))
    return C, freqs


def specgram(x, NFFT=256, Fs=2, detrend=detrend_none, window=None,
             noverlap=128, pad_to=None, sides='default', scale_by_freq=None,
             mode='psd'):
    step = NFFT - noverlap
    n_seg = max(1, (len(x) - noverlap) // step)
    freqs = _np.fft.rfftfreq(NFFT, d=1.0/Fs)
    spec = _np.zeros((len(freqs), n_seg))
    t = _np.arange(n_seg) * step / Fs
    return spec, freqs, t
